def _parse_file_header(data: bytes) -> tuple[int, int]:
    if len(data) < 14:
        raise BmpDecodeError("BMP file is too short.")
    signature = data[0:2]
    if signature not in {b"BM", b"BA", b"CI", b"CP", b"IC", b"PT"}:
        raise BmpDecodeError("Not a Windows BMP image.")
    pixel_offset = _read_u32(data, 10)
    return _read_u32(data, 2), pixel_offset

